mapper.select:
select id, plaza, publisher_user_id, category, title, status, tags, description, expected_time, expected_location, publisher_name, publisher_status, publisher_status_note, avatar_text, anonymous, verified, current_count, max_count, current_state, hope_you_can, preferred_way, gentle_replies from home_post where deleted = 0 and review_status = 'visible' and plaza = #{query.plaza}
and category = #{query.category}
and ( title like concat('%', #{query.keyword}, '%') or description like concat('%', #{query.keyword}, '%') or expected_location like concat('%', #{query.keyword}, '%') or publisher_name like concat('%', #{query.keyword}, '%') or tags like concat('%', #{query.keyword}, '%') )
order by sort_weight desc, id desc limit 20

select id, plaza, publisher_user_id, category, title, status, tags, description, expected_time, expected_location, publisher_name, publisher_status, publisher_status_note, avatar_text, anonymous, verified, current_count, max_count, current_state, hope_you_can, preferred_way, gentle_replies from home_post where deleted = 0 and review_status = 'visible' and plaza = 'vent' and id != #{id}
and category = #{category}
order by sort_weight desc, id desc limit 3
